/// ADR-013/TR-08: const-fn limb comparisons used by `const_ring_eval_w{n}`
/// to lift the comparison primitives to 0/1-valued ring indicators.
#[inline]
#[must_use]
const fn limbs_lt_3(a: Limbs<3>, b: Limbs<3>) -> bool {
    let aw = a.words();
    let bw = b.words();
    let mut i = 3;
    while i > 0 {
        i -= 1;
        if aw[i] < bw[i] {
            return true;
        }
        if aw[i] > bw[i] {
            return false;
        }
    }
    false
}

